def fibonacci(n):
    if n < 0:
        raise ValueError("n must be non-negative")
    if n <= 1:
        return n

    a, b = 0, 1

    # Iterate from MSB to LSB of n
    for bit in range(n.bit_length() - 1, -1, -1):
        # Double: compute F(2k), F(2k+1)
        c = a * ((b << 1) - a)
        d = a * a + b * b
        # If current bit is set, advance by one more step
        if (n >> bit) & 1:
            a, b = d, c + d
        else:
            a, b = c, d

    return a

