def fibonacci(n):
    if n < 0:
        raise ValueError("n must be non-negative")
    if n <= 1:
        return n

    # Start from MSB which is always 1, giving F(1)=1, F(2)=1
    a, b = 1, 1

    # Process remaining bits from second-highest to LSB
    for bit in range(n.bit_length() - 2, -1, -1):
        c = a * ((b << 1) - a)   # F(2k)
        d = a * a + b * b         # F(2k+1)
        if (n >> bit) & 1:
            a, b = d, c + d
        else:
            a, b = c, d

    return a
